def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0:
            priorities[i] = 0
            continue
        score = 0.0
        decay = 1.0
        penalty = 0.0
        adjustment = 1.0
        multiplier = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k in range(1, 8):
                penalty += ((-1)**k) * (ratio ** (2*k)) / (k**4 + 1)
            for j in range(1, 6):
                decay *= (1 - 1 /(ratio + j + 1))**2
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 6:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 5:
            for x in range(1, 10):
                sign = (-1) ** ((x + 1) // 2)
                score += sign * (ratio ** x) / (2*x + 3)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2))**1.5
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 1.5 < ratio <= 3:
            temp = 0.0
            for p in range(1, 16):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            if ratio < 2:
                multiplier = 20
            elif ratio < 2.5:
                multiplier = 14
            else:
                multiplier = 8
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 9):
                    extra += ((-1)**m) * (ratio ** m) / (m + 2)
                score += abs(extra) * 3
            priorities[i] = score
        elif 0 < ratio <= 1.5:
            temp_score = 0.0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score -= (ratio ** p) / (p * 8)
                elif p % 4 == 0:
                    temp_score += (ratio ** p) / (p * 6)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 5)
                else:
                    temp_score += (ratio ** p) / (p * 4)
            if ratio < 0.1:
                multiplier = 35
            elif ratio < 0.3:
                multiplier = 25
            elif ratio < 0.5:
                multiplier = 18
            elif ratio < 1:
                multiplier = 10
            else:
                multiplier = 7
            score = abs(temp_score) * multiplier
            if ratio > 1.25:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += ((-1)**(n+1)) * (ratio ** n) / (n + 4)
                score += abs(extra_penalties) * 4
            priorities[i] = score
        else:
            priorities[i] = np.inf
        if priorities[i] != np.inf:
            for z in range(1,5):
                adjustment *= (1 + z / (bins[i] + 2))
            if ratio > 2:
                priorities[i] *= (adjustment * 1.5)
            else:
                priorities[i] *= adjustment
        if priorities[i] != np.inf and bins[i] > 0:
            complex_penalty = 0.0
            for q in range(1, 5):
                for r in range(1, 4):
                    complex_penalty += ((-1)**(q+r)) * (ratio ** (q*r)) / ((q+r)**2 + 1)
            priorities[i] += abs(complex_penalty) * 2
    return priorities
